    21→  const [formErrors, setFormErrors] = useState<SalonFormErrors>({});
    22→
    23→  const handleErrorChange = (field: keyof SalonFormData): void => {
    24→    setFormErrors((prev) => {
    25→      const next = { ...prev };
    26→      delete next[field];
    27→      return next;
    28→    });
    29→  };
    30→
